import { chord, ribbon } from 'https://cdn.jsdelivr.net/npm/d3-chord@3.0.1/+esm';
import { arc } from 'https://cdn.jsdelivr.net/npm/d3-shape@3/+esm'; // 外圈 group 弧(d3-chord 不含)
const layout = chord().padAngle(data.padAngle ?? 0.05);
const chords = layout(data.matrix); // chords[](带 .groups)
const R = data.radius ?? 240;
const ribbonPath = ribbon().radius(R);
const arcGen = arc().innerRadius(R).outerRadius(R + 18);
// SVG:<g transform=`translate(${cx},${cy})`> 内,chords.groups 逐个 arcGen(g) 画外圈弧;chords 逐个 ribbonPath(d) 画弦带
